The error `QueryFailedError: Unknown column 'NaN' in 'field list'` occurs because the `ColumnNumericTransformer` in your backend is naively converting `null` database values into `NaN` (via `parseFloat(null)`), and/or passing `NaN` back to the database update query. MySQL treats unquoted `NaN` as a column identifier, causing the crash.

I will fix the transformer to handle nulls correctly and update the bulk import logic to be more robust against `NaN` and `0` values (using nullish coalescing instead of logical OR).

# Updated files:

## server/src/utils/transformer.ts

Correctly handle `null` and `NaN` values during database serialization/deserialization.

```typescript
export class ColumnNumericTransformer {
  to(data: number | null | undefined): number | null {
    // Convert NaN or null/undefined to database NULL
    if (data === null || data === undefined || (typeof data === 'number' && isNaN(data))) {
      return null;
    }
    return data;
  }

  from(data: string | null | undefined): number | null {
    // Handle database NULLs gracefully
    if (data === null || data === undefined) {
      return null;
    }
    const float = parseFloat(data);
    // Ensure we don't return NaN to the application layer
    return isNaN(float) ? null : float;
  }
}
```

## server/src/routes/product.routes.ts

Update bulk import logic to prevent logic bugs with `0` values (using `??` instead of `||`) and ensure numeric safety.

```typescript
import { Router } from 'express';
import { ProductService } from '../services/productService';
import { validate } from '../middleware/validate';
import { authenticate, authorize } from '../middleware/auth';
import { z } from 'zod';
import { AppDataSource } from '../config/database';
import { Product } from '../entities/Product';
import { Category } from '../entities/Category';
import { ProductStock } from '../entities/ProductStock';
import { Branch } from '../entities/Branch';
import { OemNumber } from '../entities/OemNumber';
import { Vehicle } from '../entities/Vehicle'; 
import { createProductSchema, updateProductSchema } from '../schemas/product.schema';

const router = Router();

// GET /api/products
router.get('/', async (req, res) => {
    try {
        const query = req.query.q as string || '';
        const category = req.query.category as string || 'All';
        const page = parseInt(req.query.page as string) || 1;
        const limit = parseInt(req.query.limit as string) || 100;

        const result = await ProductService.getAllProducts(query, category, page, limit);
        res.json(result); 
    } catch (error) {
        console.error(error);
        res.status(500).json({ error: 'Failed to fetch products' });
    }
});

// GET /api/products/sku/:sku
router.get('/sku/:sku', async (req, res) => {
    try {
        const products = await ProductService.getAllProducts(req.params.sku);
        const product = (products as any).data ? (products as any).data.find((p: any) => p.sku === req.params.sku) : null;

        if (!product) return res.status(404).json({ error: 'SKU not found' });
        res.json([product]);
    } catch (error) {
         res.status(500).json({ error: 'Search failed' });
    }
});

// GET /api/products/:id
router.get('/:id', async (req, res) => {
    try {
        const product = await ProductService.getProductById(req.params.id);
        if (!product) return res.status(404).json({ error: 'Product not found' });
        res.json(product);
    } catch (error) {
        res.status(500).json({ error: 'Server error' });
    }
});

// POST /api/products (Admin Only)
router.post('/', authenticate, authorize(['ADMIN', 'MANAGER']), validate(createProductSchema), async (req, res) => {
    try {
        // Inject branchId from authenticated user to initialize stock
        const payload = { 
            ...req.body, 
            branchId: req.user?.branch?.id 
        };

        const product = await ProductService.createProduct(payload);
        res.status(201).json(product);
    } catch (error: any) {
        res.status(500).json({ error: error.message || 'Failed to create product' });
    }
});

// PUT /api/products/:id (Admin Only)
router.put('/:id', authenticate, authorize(['ADMIN', 'MANAGER']), validate(updateProductSchema), async (req, res) => {
    try {
        // Enable active sync: Pass branchId so stock can be updated alongside details
        const payload = {
            ...req.body,
            branchId: req.user?.branch?.id
        };
        const product = await ProductService.updateProduct(req.params.id, payload);
        res.json(product);
    } catch (error: any) {
        res.status(500).json({ error: error.message || 'Failed to update product' });
    }
});

// DELETE /api/products/:id (Admin Only)
router.delete('/:id', authenticate, authorize(['ADMIN', 'MANAGER']), async (req, res) => {
    try {
        await ProductService.deleteProduct(req.params.id);
        res.json({ message: 'Product deleted successfully' });
    } catch (error: any) {
        res.status(500).json({ error: error.message || 'Failed to delete product' });
    }
});

// --- BULK IMPORT ROUTE ---
const bulkImportSchema = z.object({
    branchId: z.string(),
    products: z.array(z.object({
        sku: z.string(),
        name: z.string(),
        category: z.string(),
        // Explicitly check for finite numbers to reject NaN
        price: z.number().finite(),
        costPrice: z.number().finite().optional(),
        wholesalePrice: z.number().finite().optional(),
        description: z.string().optional(),
        oemNumbers: z.string().optional(), 
        compatibility: z.string().optional(),
        quantity: z.number().finite().optional(),
        lowStockThreshold: z.number().finite().optional(),
        imageUrl: z.string().optional()
    }))
});

router.post('/bulk', authenticate, authorize(['ADMIN', 'MANAGER']), validate(bulkImportSchema), async (req, res) => {
    const { branchId, products } = req.body;
    const queryRunner = AppDataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
        const branch = await queryRunner.manager.findOneBy(Branch, { id: branchId });
        if (!branch) throw new Error('Invalid Branch ID');

        let createdCount = 0;
        let updatedCount = 0;

        for (const item of products) {
            let category = await queryRunner.manager.findOneBy(Category, { name: item.category });
            if (!category) {
                category = queryRunner.manager.create(Category, { name: item.category });
                await queryRunner.manager.save(category);
            }

            let product = await queryRunner.manager.findOneBy(Product, { sku: item.sku });

            // Helper to sanitize numeric inputs to avoid NaN in DB
            const safeNum = (val: number | undefined | null, defaultVal: number | null = null) => {
                if (typeof val === 'number' && isFinite(val)) return val;
                return defaultVal;
            };

            if (product) {
                // Update existing
                product.name = item.name;
                product.price = safeNum(item.price, 0) as number;

                // Use nullish coalescing (??) to allow 0 as a valid value
                product.costPrice = safeNum(item.costPrice, product.costPrice) as number;
                product.wholesalePrice = safeNum(item.wholesalePrice, product.wholesalePrice) as number | undefined;

                product.description = item.description || product.description;
                product.category = category;
                if (item.imageUrl) product.imageUrl = item.imageUrl;

                await queryRunner.manager.save(product);
                updatedCount++;
            } else {
                // Create new
                product = new Product();
                product.sku = item.sku;
                product.name = item.name;
                product.price = safeNum(item.price, 0) as number;
                product.costPrice = safeNum(item.costPrice, 0) as number;
                // Default wholesale to price if not provided, safely
                product.wholesalePrice = safeNum(item.wholesalePrice, item.price) as number | undefined;

                product.description = item.description || '';
                product.category = category;
                product.imageUrl = item.imageUrl || '';

                await queryRunner.manager.save(product);
                createdCount++;
            }

            if (item.oemNumbers) {
                await queryRunner.manager.delete(OemNumber, { product: { id: product.id } });
                const oems = item.oemNumbers.split(',').map((code: string) => {
                    const o = new OemNumber();
                    o.code = code.trim();
                    o.product = product!;
                    return o;
                });
                await queryRunner.manager.save(oems);
            }

            if (item.compatibility) {
                const compatStrings = item.compatibility.split(',').map((s: string) => s.trim()).filter((s: string) => s);
                const vehicles = [];
                for (const comp of compatStrings) {
                    const parts = comp.split(' ');
                    const make = parts.length > 1 ? parts[0] : 'Generic';
                    const model = parts.length > 1 ? parts.slice(1).join(' ') : comp;

                    let v = await queryRunner.manager.findOneBy(Vehicle, { make, model });
                    if (!v) {
                        v = queryRunner.manager.create(Vehicle, { make, model });
                        await queryRunner.manager.save(v);
                    }
                    vehicles.push(v);
                }
                product.vehicles = vehicles;
                await queryRunner.manager.save(product);
            }

            if (item.quantity !== undefined) {
                let stock = await queryRunner.manager.findOne(ProductStock, {
                    where: { product: { id: product.id }, branch: { id: branch.id } }
                });

                if (!stock) {
                    stock = new ProductStock();
                    stock.product = product;
                    stock.branch = branch;
                    stock.quantity = 0;
                }
                stock.quantity = safeNum(item.quantity, 0) as number;
                stock.lowStockThreshold = safeNum(item.lowStockThreshold, 5) as number;
                await queryRunner.manager.save(stock);
            }
        }

        await queryRunner.commitTransaction();
        res.json({ message: 'Bulk import successful', created: createdCount, updated: updatedCount });

    } catch (error: any) {
        await queryRunner.rollbackTransaction();
        console.error(error);
        res.status(500).json({ error: error.message || 'Bulk import failed' });
    } finally {
        await queryRunner.release();
    }
});

export default router;
```

The error `TS18048: 'product.quantity' is possibly 'undefined'` occurs because the TypeScript interface for `Product` defines `quantity` as an optional property (`number | undefined`).

When rendering the logic to check stock levels, I need to ensure a default value is used if `quantity` is undefined. I have updated the conditions to use `(product.quantity || 0)` which forces it to be a number for the comparison.

# Updated files:

## components/admin/ProductManager.tsx

Fix TypeScript error by defaulting `product.quantity` to 0 during comparisons.

```tsx
// ...
                                <td className="px-6 py-3">
                                    {(product.quantity || 0) > 5 ? (
                                        <span className="text-green-600 font-bold text-[10px] uppercase bg-green-50 px-2 py-1 rounded">{product.quantity} In Stock</span>
                                    ) : (product.quantity || 0) > 0 ? (
                                        <span className="text-orange-600 font-bold text-[10px] uppercase bg-orange-50 px-2 py-1 rounded">{product.quantity} Low Stock</span>
                                    ) : (
                                        <span className="text-red-600 font-bold text-[10px] uppercase bg-red-50 px-2 py-1 rounded">Out of Stock</span>
                                    )}
                                </td>
// ...

The previous error occurred because the file `components/admin/ProductManager.tsx` was accidentally overwritten with a code snippet instead of the full file content during the last update. This broke the module export, causing `App.tsx` to fail when trying to import it, and caused the syntax errors because the snippet relied on variables (`product`) that weren't defined in the global scope of the file.

I am restoring the **full content** of `components/admin/ProductManager.tsx` with the TypeScript fix applied correctly inside the component.

# Updated files:

## components/admin/ProductManager.tsx

Restored full file content with fixed stock quantity checks.

```tsx
import React, { useState, useEffect, useRef } from 'react';
import { Search, Plus, Edit2, Trash2, X, Save, Loader2, UploadCloud, Download, Upload, Package, ChevronLeft, ChevronRight } from 'lucide-react';
import { Product } from '../../types';
import { apiClient } from '../../utils/apiClient';

const ProductManager: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<{id: string, name: string}[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Pagination State
  const [pagination, setPagination] = useState({ page: 1, limit: 20, total: 0, pages: 1 });

  // Editor State
  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [formData, setFormData] = useState<any>({});
  const [oemString, setOemString] = useState(''); 
  const [compatString, setCompatString] = useState(''); 

  // Import/Export State
  const [isImporting, setIsImporting] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  // Refs for file inputs
  const csvInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);

  const fetchProducts = async (page = 1) => {
    setIsLoading(true);
    try {
        const res = await apiClient.get(`/products?q=${searchTerm}&page=${page}&limit=${pagination.limit}`);
        if (res.data && res.data.data) {
            setProducts(res.data.data);
            setPagination(res.data.meta);
        } else {
            // Fallback for non-paginated response
            setProducts(res.data);
        }
    } catch (error) {
        console.error('Failed to fetch products', error);
    } finally {
        setIsLoading(false);
    }
  };

  const fetchCategories = async () => {
      try {
          const res = await apiClient.get('/categories');
          setCategories(res.data);
      } catch (error) {
          console.error('Failed to fetch categories', error);
      }
  };

  useEffect(() => {
    const debounce = setTimeout(() => fetchProducts(1), 500);
    return () => clearTimeout(debounce);
  }, [searchTerm]);

  useEffect(() => {
      fetchCategories();
  }, []);

  const handlePageChange = (newPage: number) => {
      if (newPage >= 1 && newPage <= pagination.pages) {
          fetchProducts(newPage);
      }
  };

  const handleAddNew = () => {
    setFormData({
        name: '', sku: '', price: '', costPrice: '', wholesalePrice: '', quantity: '',
        description: '', category: categories[0]?.name || 'General', image: '', images: [], oemNumbers: [], compatibility: []
    });
    setOemString('');
    setCompatString('');
    setIsEditorOpen(true);
  };

  const handleEdit = (product: Product) => {
    setFormData({
        ...product,
        images: product.images || (product.image ? [product.image] : [])
    });
    setOemString(product.oemNumbers ? product.oemNumbers.join(', ') : '');
    setCompatString(product.compatibility ? product.compatibility.join(', ') : '');
    setIsEditorOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this product?')) return;

    try {
        await apiClient.delete(`/products/${id}`);
        fetchProducts(pagination.page);
        alert('Product deleted successfully.');
    } catch (error: any) {
        alert(error.response?.data?.error || 'Failed to delete product.');
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, field: 'image' | 'video') => {
      const file = e.target.files?.[0];
      if (!file) return;

      setIsUploading(true);
      const uploadData = new FormData();
      uploadData.append('image', file);

      try {
          const res = await apiClient.post('/upload', uploadData);

          if (res.data && res.data.url) {
              const url = res.data.url;
              if (field === 'image') {
                  setFormData((prev: any) => {
                      const currentImages = prev.images || [];
                      const updatedImages = [...currentImages, url];
                      return {
                          ...prev,
                          image: prev.image ? prev.image : url,
                          images: updatedImages
                      };
                  });
              } else {
                  setFormData((prev: any) => ({ ...prev, videoUrl: url }));
              }
          } else {
              throw new Error('Invalid response from server');
          }
      } catch (error: any) {
          console.error("Upload Error:", error);
          alert('Upload failed: ' + (error.response?.data?.error || error.message));
      } finally {
          setIsUploading(false);
          if (imageInputRef.current) imageInputRef.current.value = '';
      }
  };

  const handleSetPrimaryImage = (url: string) => {
      setFormData((prev: any) => ({ ...prev, image: url }));
  };

  const handleRemoveImage = (urlToRemove: string) => {
      setFormData((prev: any) => {
          const updatedImages = prev.images.filter((img: string) => img !== urlToRemove);
          let newPrimary = prev.image;
          if (prev.image === urlToRemove) {
              newPrimary = updatedImages.length > 0 ? updatedImages[0] : '';
          }
          return {
              ...prev,
              images: updatedImages,
              image: newPrimary
          };
      });
  };

  // Robust number cleaner to prevent NaN
  const cleanNumber = (str: any) => {
      if (str === null || str === undefined || str === '') return 0;
      // Remove all non-numeric chars except digits, minus sign, and dot
      // This strips currency symbols, commas, etc.
      const clean = String(str).replace(/[^\d.-]/g, '');
      if (clean === '') return 0;
      const num = parseFloat(clean);
      return (typeof num === 'number' && isFinite(num)) ? num : 0;
  };

  const handleSave = async () => {
    if (!formData.name || !formData.sku || (!formData.price && formData.price !== 0)) {
        alert('Please fill in all required fields (Name, SKU, Price).');
        return;
    }

    setIsSaving(true);
    try {
        const payload = {
            ...formData,
            oemNumbers: oemString.split(',').map(s => s.trim()).filter(s => s.length > 0),
            compatibility: compatString.split(',').map(s => s.trim()).filter(s => s.length > 0),
            price: cleanNumber(formData.price),
            costPrice: cleanNumber(formData.costPrice),
            wholesalePrice: cleanNumber(formData.wholesalePrice),
            quantity: cleanNumber(formData.quantity),
            imageUrl: formData.image, 
            images: formData.images 
        };

        if (formData.id) {
            await apiClient.put(`/products/${formData.id}`, payload);
        } else {
            await apiClient.post('/products', payload);
        }

        setIsEditorOpen(false);
        fetchProducts(pagination.page); 
    } catch (error: any) {
        alert(error.response?.data?.error || 'Failed to save product. Check inputs.');
        console.error(error);
    } finally {
        setIsSaving(false);
    }
  };

  // --- CSV FUNCTIONS ---

  const handleExport = async () => {
      setIsExporting(true);
      try {
          const res = await apiClient.get('/products?limit=100000');
          const allProducts = res.data.data || res.data || [];

          const headers = ['SKU', 'Name', 'Category', 'Price (Retail)', 'Quantity', 'Cost Price', 'Wholesale Price', 'Description', 'OEM Numbers', 'Compatible Vehicles', 'Image URL'];

          const rows = allProducts.map((p: any) => [
              p.sku,
              `"${p.name.replace(/"/g, '""')}"`,
              p.category,
              p.price,
              p.quantity || 0,
              p.costPrice || 0,
              p.wholesalePrice || 0,
              `"${(p.description || '').replace(/"/g, '""')}"`,
              `"${(p.oemNumbers || []).join('|')}"`,
              `"${(p.compatibility || []).join('|')}"`,
              p.image
          ].join(','));

          const csvContent = [headers.join(','), ...rows].join('\n');
          const blob = new Blob([csvContent], { type: 'text/csv' });
          const url = window.URL.createObjectURL(blob);
          const a = document.createElement('a');
          a.href = url;
          a.download = `masuma_inventory_export_${new Date().toISOString().slice(0,10)}.csv`;
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);
          window.URL.revokeObjectURL(url);
      } catch (error) {
          alert('Export failed. Please try again.');
      } finally {
          setIsExporting(false);
      }
  };

  const handleImportClick = () => {
      csvInputRef.current?.click();
  };

  const parseCSVLine = (line: string) => {
      const result = [];
      let current = '';
      let inQuote = false;

      for (let i = 0; i < line.length; i++) {
          const char = line[i];
          if (char === '"') {
              inQuote = !inQuote;
          } else if (char === ',' && !inQuote) {
              result.push(current.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));
              current = '';
          } else {
              current += char;
          }
      }
      result.push(current.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));
      return result;
  };

  const handleImportFile = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setIsImporting(true);
      const reader = new FileReader();

      reader.onload = async (evt) => {
          const text = evt.target?.result as string;
          const lines = text.split('\n');
          if (lines.length < 2) {
              alert("CSV file is empty or invalid format.");
              setIsImporting(false);
              return;
          }

          const headers = parseCSVLine(lines[0]).map(h => h.toLowerCase().trim());

          const getColumnIndex = (candidates: string[], exclusions: string[] = []) => {
              return headers.findIndex(h => {
                  const matchesCandidate = candidates.some(c => h.includes(c));
                  const matchesExclusion = exclusions.some(e => h.includes(e));
                  return matchesCandidate && !matchesExclusion;
              });
          };

          const importedProducts = [];

          for (let i = 1; i < lines.length; i++) {
              if (!lines[i].trim()) continue;
              const values = parseCSVLine(lines[i]);

              const getRawValue = (candidates: string[], exclusions: string[] = []) => {
                  const idx = getColumnIndex(candidates, exclusions);
                  if (idx === -1) return '';
                  let val = values[idx] || '';
                  return val.replace(/^"|"$/g, '').replace(/""/g, '"').trim();
              };

              const sku = getRawValue(['sku', 'part no', 'code', 'part_number']);
              const name = getRawValue(['name', 'product', 'description', 'item', 'title']) || 'Imported Product';

              if (sku) {
                  // Price Logic - Robust check to avoid NaN
                  const priceStr = getRawValue(['retail', 'selling', 'price', 'srp'], ['cost', 'wholesale', 'buying']);
                  const price = cleanNumber(priceStr);

                  const costStr = getRawValue(['cost', 'buying', 'purchase']);
                  const costPrice = cleanNumber(costStr);

                  const wholesaleStr = getRawValue(['wholesale', 'trade', 'dealer']);
                  const wholesalePrice = cleanNumber(wholesaleStr);

                  const quantityStr = getRawValue(['qty', 'quantity', 'stock', 'count']);
                  const quantity = Math.floor(cleanNumber(quantityStr));

                  // Oems (Handle pipe or comma sep)
                  const oemRaw = getRawValue(['oem', 'cross', 'ref', 'original']);
                  const oemNumbers = oemRaw.replace(/\|/g, ',');

                  const compatRaw = getRawValue(['vehicle', 'fit', 'compat', 'model']);
                  const compatibility = compatRaw.replace(/\|/g, ',');

                  const category = getRawValue(['category', 'group', 'cat']) || 'General';
                  const description = getRawValue(['desc', 'detail', 'info']);
                  const imageUrl = getRawValue(['image', 'url', 'photo', 'link']);

                  importedProducts.push({
                      sku,
                      name,
                      category,
                      price, // Guaranteed number
                      costPrice,
                      wholesalePrice,
                      description,
                      quantity,
                      oemNumbers,
                      compatibility,
                      imageUrl
                  });
              }
          }

          try {
              // Inject Branch ID from User Session
              const userStr = localStorage.getItem('masuma_user');
              const user = userStr ? JSON.parse(userStr) : {};
              const branchId = user.branch?.id;

              if (!branchId) throw new Error("Branch ID missing. Please relogin.");

              const res = await apiClient.post('/products/bulk', { 
                  branchId,
                  products: importedProducts 
              });

              alert(`Import Successful!\nCreated: ${res.data.created}\nUpdated: ${res.data.updated}`);
              fetchProducts(1);
          } catch (error: any) {
              console.error(error);
              alert('Import Failed: ' + (error.response?.data?.error || error.message));
          } finally {
              setIsImporting(false);
              if (csvInputRef.current) csvInputRef.current.value = '';
          }
      };

      reader.readAsText(file);
  };

  return (
    <div className="h-full flex flex-col">
        <div className="flex justify-between items-center mb-6">
            <div>
                <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase">Product Manager</h2>
                <p className="text-sm text-gray-500">Manage catalog, pricing, and specifications.</p>
            </div>
            <div className="flex gap-2">
                <button 
                    onClick={handleExport}
                    disabled={isExporting}
                    className="bg-white border border-gray-300 text-gray-600 px-4 py-2 rounded font-bold uppercase text-xs hover:bg-gray-50 flex items-center gap-2"
                >
                    {isExporting ? <Loader2 className="animate-spin" size={16}/> : <Download size={16} />} Export CSV
                </button>
                <div className="relative">
                    <input 
                        type="file" 
                        ref={csvInputRef} 
                        className="hidden" 
                        accept=".csv"
                        onChange={handleImportFile}
                    />
                    <button 
                        onClick={handleImportClick}
                        disabled={isImporting}
