          "seller": {
              "@type": "Organization",
              "name": "Masuma Autoparts East Africa"
          }
      }
  };

  return (
    <>
      <SEO 
        title={product.name} 
        description={product.description.substring(0, 160)} 
        image={product.image}
        type="product"
        schema={productSchema}
      />

      <div className="fixed inset-0 z-[2000] flex items-center justify-center p-4 sm:p-6">
        <div 
