import React, { useState, useEffect } from 'react';
import { X, Check, AlertTriangle, Truck, MessageCircle, Plus, Minus, ArrowRight, Share2, Facebook, Twitter } from 'lucide-react';
import { Product } from '../types';
import QuoteModal from './QuoteModal';
import Price from './Price';
import { apiClient } from '../utils/apiClient';
import SEO from './SEO';

interface QuickViewProps {
  product: Product | null;
  isOpen: boolean;
  onClose: () => void;
  addToCart: (product: Product, quantity?: number) => void;
  onSwitchProduct?: (product: Product) => void;
}

const QuickView: React.FC<QuickViewProps> = ({ product, isOpen, onClose, addToCart, onSwitchProduct }) => {
  const [isQuoteModalOpen, setIsQuoteModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);
  const [relatedProducts, setRelatedProducts] = useState<Product[]>([]);
  const [isLoadingRelated, setIsLoadingRelated] = useState(false);

  // Gallery State
  const [activeImage, setActiveImage] = useState('');
  const [gallery, setGallery] = useState<string[]>([]);

  // 1. Manage URL State for Deep Linking & SEO
  useEffect(() => {
    if (isOpen && product) {
        // Update URL to /?product=ID without reloading
        const newUrl = `${window.location.pathname}?product=${product.id}`;
        window.history.replaceState({ path: newUrl }, '', newUrl);

        setQuantity(1);

        // Initialize Gallery
        const imgs = product.images && product.images.length > 0 ? product.images : [product.image];
        setGallery(imgs);
        setActiveImage(imgs[0]);

        fetchRelatedProducts(product);
    } else if (!isOpen) {
        // Revert URL when closed
        const cleanUrl = window.location.pathname;
        window.history.replaceState({ path: cleanUrl }, '', cleanUrl);
    }
  }, [isOpen, product]);

  const fetchRelatedProducts = async (currentProduct: Product) => {
      setIsLoadingRelated(true);
      try {
          const res = await apiClient.get(`/products?category=${currentProduct.category}&limit=10`);
          const allProducts = res.data.data || res.data || [];
          const filtered = allProducts.filter((p: Product) => p.id !== currentProduct.id);
          setRelatedProducts(filtered);
      } catch (error) {
          console.error("Failed to fetch related products", error);
          setRelatedProducts([]);
      } finally {
          setIsLoadingRelated(false);
      }
  };

  if (!isOpen || !product) return null;

  const handleQuantityChange = (delta: number) => {
    setQuantity(prev => Math.max(1, prev + delta));
  };

  const handleAddToCart = () => {
    addToCart(product, quantity);
    onClose();
  };

  const handleSwitch = (p: Product) => {
      if (onSwitchProduct) {
          const contentDiv = document.getElementById('quickview-content');
          if (contentDiv) contentDiv.scrollTop = 0;
          onSwitchProduct(p);
      }
  };

  // Social Share Logic
  const shareUrl = `${window.location.origin}/?product=${product.id}`;
  const shareText = `Check out this ${product.name} at Masuma Autoparts EA!`;

  const handleSocialShare = (platform: 'whatsapp' | 'facebook' | 'twitter') => {
      let url = '';
      switch (platform) {
          case 'whatsapp':
              url = `https://wa.me/?text=${encodeURIComponent(`${shareText} ${shareUrl}`)}`;
              break;
          case 'facebook':
              url = `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(shareUrl)}`;
              break;
          case 'twitter':
              url = `https://twitter.com/intent/tweet?text=${encodeURIComponent(shareText)}&url=${encodeURIComponent(shareUrl)}`;
              break;
      }
      window.open(url, '_blank', 'width=600,height=400');
  };

  // Construct Product Schema for Google
  const productSchema = {
      "@context": "https://schema.org/",
      "@type": "Product",
      "name": product.name,
      "image": product.images || [product.image],
      "description": product.description,
      "sku": product.sku,
      "mpn": product.sku,
      "brand": {
